import json

docs = []
with open(locals()['var_function-call-10776937919951051109'], 'r') as f:
    docs.extend(json.load(f))
with open(locals()['var_function-call-17406117685719211180'], 'r') as f:
    docs.extend(json.load(f))

targets = [
    "A Trip to the Moon: Personalized Animated Movies for Self-reflection.txt",
    "ClimbSense: Automatic Climbing Route Recognition Using Wrist-worn Inertia Measurement Units.txt",
    "Contextual Influences on the Use and Non-Use of Digital Technology While Exercising at the Gym.txt",
    "Designing in the Dark: Eliciting Self-tracking Dimensions for Understanding Enigmatic Disease.txt"
]

results = {}
for doc in docs:
    if doc['filename'] in targets:
        text = doc['text']
        head = text[:3000]
        # Find matches
        matches = []
        if "CHI 20" in head: matches.append(f"CHI 20 at {head.find('CHI 20')}")
        if "CHI '1" in head: matches.append(f"CHI '1 at {head.find('CHI \'1')}")
        if "CHI'1" in head: matches.append(f"CHI'1 at {head.find('CHI\'1')}")
        if "CHI Conference" in head: matches.append("CHI Conference")
        if "Conference on Human Factors" in head: matches.append("Conference on Human Factors")

        results[doc['filename']] = matches

print("__RESULT__:")
print(json.dumps(results))

